import 'dart:convert';
import 'package:flutter/material.dart';

class AppImages {
  AppImages._();

  static final _fondoLoginBytes      = base64Decode('');
  static final _iconoBytes           = base64Decode('');
  static final _logoCompletoBytes    = base64Decode('');
  static final _logoTextoBytes       = base64Decode('');

  /// Imagen de fondo para splash y login
  static Image fondoLogin({double? width, double? height, BoxFit fit = BoxFit.cover}) =>
      Image.memory(_fondoLoginBytes, width: width, height: height, fit: fit);

  /// Solo el icono triangular (fondo transparente)
  static Image icono({double? width, double? height}) =>
      Image.memory(_iconoBytes, width: width, height: height, fit: BoxFit.contain);

  /// Logo completo icono + texto (fondo transparente)
  static Image logoCompleto({double? width, double? height}) =>
      Image.memory(_logoCompletoBytes, width: width, height: height, fit: BoxFit.contain);

  /// Solo el texto TriAlert
  static Image logoTexto({double? width, double? height}) =>
      Image.memory(_logoTextoBytes, width: width, height: height, fit: BoxFit.contain);
}
